public str postInvoice(str _ARAPRef)
{
    str arAPRef = _ARAPRef;

    ETG_ARAP_MSGHEADER headerMsg;
    ETG_ARAP_MSGLINES linesMsg;

    LedgerJournalTable ledgerJournalTable, ledgerJournalTableVal;
    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalName ledgerJournalName;
    CustTable custTable, custTableLoc;
    VendTable vendTable;
    NumberSeq numberseq;
    Voucher voucher;
    DimensionDynamicAccount ledgerDim;
    str integrationMessage;
    ETGIntegrationJournalTypes journalTypes;
    ETG_CXCERPBusinessUnitMapping businessUnitMap;
    ETG_CXCERPCostCenterMapping costCenterMap;
    InventTable inventTableLoc;
    InventPosting inventPosting, inventPostingLoc;
    ETGIntegrationDocumentCause integrationDocumentCause;
    VendPaymFee vendPaymFee;
    str mainAccount;

    select * from headerMsg where headerMsg.ETGARAPREF == arAPRef;

    changecompany(headerMsg.ETGLegalEntity)
    {
        select * from journalTypes
                where journalTypes.ETGDocuType == headerMsg.ETGDocuType;

        select firstonly ledgerJournalName
                where ledgerJournalName.JournalName == journalTypes.ETGJournalType;

        select firstonly businessUnitMap
                where businessUnitMap.ETGCXCProfitCenter == headerMsg.ETGPROFITCENTERGR;

        select firstonly costCenterMap
            where costCenterMap.ETGCXCProfitCenter == headerMsg.ETGPROFITCENTERGR;
        // Header
        ledgerJournalTable = null;
        ledgerJournalTable.company(headerMsg.ETGLegalEntity);
        ledgerJournalTable.JournalName = ledgerJournalName.JournalName;
        ledgerJournalTable.initFromLedgerJournalName();
        ledgerJournalTable.NumberSequenceTable = ledgerJournalName.NumberSequenceTable;
        ledgerJournalTable.insert();

        if (ledgerJournalTable.RecId)
        {
            select * from linesMsg
                    where linesMsg.AxIntegrationHeaderRecId == headerMsg.AXHeaderRecId;
            {
                // Line
                ledgerJournalTrans = null;
                ledgerJournalTrans.Company = headerMsg.ETGLegalEntity;
                ledgerJournalTrans.JournalNum = ledgerJournalTable.JournalNum;
                ledgerJournalTrans.TransDate = str2Date(headerMsg.AXDocDate, 321);
                ledgerJournalTrans.DocumentDate = str2Date(headerMsg.AXDocDate, 321);
                ledgerJournalTrans.Due = str2Date(headerMsg.AXDueDate, 321);
                ledgerJournalTrans.LineNum = LedgerJournalTrans::lastLineNum(ledgerJournalTrans.JournalNum);

                voucher = new JournalVoucherNum(JournalTableData::newTable(ledgerJournalTable)).getNew(true);

                ledgerJournalTrans.Voucher = voucher;
                ledgerJournalTrans.CurrencyCode = linesMsg.ETGCURRENCY;
                ledgerJournalTrans.Txt = linesMsg.ETGDESCRIPTION + "QTY" + headerMsg.AXTotalQty;
                ledgerJournalTrans.Qty = str2Num(headerMsg.AXTotalQty);
                ledgerJournalTrans.AmountCurDebit = abs(str2Num(headerMsg.AXNetAmount));
                ledgerJournalTrans.Invoice = headerMsg.ETGARAPREF;
                ledgerJournalTrans.Payment = headerMsg.ETGPAYMTERMS;
                ledgerJournalTrans.ETGIntegrationContractNumber = headerMsg.ETGCONTRACTNUMBER;
                ledgerJournalTrans.ExchRate = this.validateExchRate(headerMsg.RecId);
                ledgerJournalTrans.PostingProfile = "GEN";

                ledgerJournalTrans.TaxItemGroup = "ALL";
                ledgerJournalTrans.TaxGroup = linesMsg.ETGTAXCODE;
                ledgerJournalTrans.taxAmountJournal();

                select * from custTable where custTable.ETGCxcCounterPartyMapping == headerMsg.ETGCOUNTERPARTY;

                ledgerJournalTrans.AccountType = LedgerJournalACType::Cust;
                ledgerDim = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(custTable.AccountNum, LedgerJournalACType::Cust);
                ledgerJournalTrans.LedgerDimension = ledgerDim;
                mainAccount = null;

                if(headerMsg.ETGDOCUMENTCAUSE == "washout Invoice"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Washout Correction"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Bypass Invoice"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Circle Invoice")
                {
                    ledgerJournalTrans.OffsetAccountType = LedgerJournalACType::Ledger;

                    select firstonly integrationDocumentCause
                        where integrationDocumentCause.ETGDocumentCause == headerMsg.ETGDOCUMENTCAUSE;

                    mainAccount = integrationDocumentCause.ETGLedgerCode;
                }
                else
                {
                    if((mainAccount == "") && (linesMsg.ETGLINETYPE == "Inventory" || linesMsg.ETGLINETYPE == "Financial"))
                    {
                        inventTableLoc = InventTable::find(linesMsg.ETGCOMMODITY);
                        select * from custTableLoc where custTableLoc.AccountNum == custTable.AccountNum;

                        select * from inventPosting where inventPosting.ItemRelation == inventTableLoc.itemGroupId()
                        && inventPosting.InventAccountType == InventAccountType::SalesRevenue
                        && inventPosting.CustVendRelation == custTableLoc.CustGroup
                        && inventPosting.ItemCode == InventPostingItemCode::GroupId
                        && inventPosting.CustVendCode == TableGroupAll::GroupId;
                        if(inventPosting)
                        {
                            ledgerJournalTrans.OffsetAccountType = LedgerJournalACType::Ledger;
                            mainAccount = LedgerDimensionFacade::getMainAccountFromLedgerDimension(inventPosting.LedgerDimension).MainAccountId;
                        }
                        if(!inventPosting)
                        {
                            select * from inventPostingLoc where inventPostingLoc.ItemRelation == inventTableLoc.itemGroupId()
                                && inventPostingLoc.InventAccountType == InventAccountType::SalesRevenue
                                && inventPostingLoc.CustVendRelation == ""
                                && inventPostingLoc.ItemCode == InventPostingItemCode::GroupId
                                && inventPostingLoc.CustVendCode == TableGroupAll::All;
                            if(inventPostingLoc)
                            {
                                ledgerJournalTrans.OffsetAccountType = LedgerJournalACType::Ledger;
                                mainAccount = LedgerDimensionFacade::getMainAccountFromLedgerDimension(inventPostingLoc.LedgerDimension).MainAccountId;
                            }
                            else
                            {
                                Info(strFmt("Ledger account is not available for the Commodity group %1", linesMsg.ETGCOMMODITY));
                            }
                        }
                    }
                    else if((mainAccount == "") && (linesMsg.ETGLINETYPE  == "MiscCharges"))
                    {
                        select * from vendPaymFee
                            where vendPaymFee.FeeId == linesMsg.ETGCOSTCODE;
                        if(vendPaymFee)
                        {
                            ledgerJournalTrans.OffsetAccountType = LedgerJournalACType::Ledger;
                            mainAccount = LedgerDimensionFacade::getMainAccountFromLedgerDimension(vendPaymFee.LedgerDimension).MainAccountId;
                        }
                    }
                }

                DimensionDynamicAccount ledgerDimension;

                container cont = [businessUnitMap.ETGERPVerticle,
                                      businessUnitMap.ETGERPBusinessUnit,
                                      "",linesMsg.ETGCOMMODITY, "","","", "",
                                      costCenterMap.ETGERPCostCenter,"",""];
                ledgerDimension = this.validGenerateLedgerDimension(mainAccount, cont);
                ledgerJournalTrans.OffsetLedgerDimension = ledgerDimension;
                ledgerJournalTrans.DefaultDimension = this.createDefaultDimension(businessUnitMap.ETGERPVerticle,businessUnitMap.ETGERPBusinessUnit,costCenterMap.ETGERPCostCenter,linesMsg.ETGCOMMODITY);
                ledgerJournalTrans.insert();

            }
            select * from ledgerJournalTableVal
                    where ledgerJournalTableVal.JournalNum == ledgerJournalTable.JournalNum;
        }
    }

    return ledgerJournalTableVal.JournalNum;
}

