                voucher = new JournalVoucherNum(JournalTableData::newTable(ledgerJournalTable)).getNew(true);

                ledgerJournalTrans.Voucher = voucher;
                ledgerJournalTrans.CurrencyCode = linesMsg.ETGCURRENCY;
                ledgerJournalTrans.Txt = linesMsg.ETGDESCRIPTION + "QTY" + headerMsg.AXTotalQty;
                ledgerJournalTrans.Qty = str2Num(headerMsg.AXTotalQty);
                ledgerJournalTrans.AmountCurDebit = abs(str2Num(linesMsg.AxAmount));
                ledgerJournalTrans.Invoice = headerMsg.ETGARAPREF;
                ledgerJournalTrans.Payment = headerMsg.ETGPAYMTERMS;
                ledgerJournalTrans.ETGIntegrationContractNumber = headerMsg.ETGCONTRACTNUMBER;
                ledgerJournalTrans.ExchRate = this.validateExchRate(headerMsg.RecId);
                ledgerJournalTrans.PostingProfile = "GEN";

                ledgerJournalTrans.TaxItemGroup = "ALL";
                ledgerJournalTrans.TaxGroup = linesMsg.ETGTAXCODE;
                ledgerJournalTrans.taxAmountJournal();

                select * from custTable where custTable.ETGCxcCounterPartyMapping == headerMsg.ETGCOUNTERPARTY;

                ledgerJournalTrans.AccountType = LedgerJournalACType::Cust;
                ledgerDim = LedgerDynamicAccountHelper::getDynamicAccountFromAccountNumber(custTable.AccountNum, LedgerJournalACType::Cust);
                ledgerJournalTrans.LedgerDimension = ledgerDim;
                mainAccount = null;

                if(headerMsg.ETGDOCUMENTCAUSE == "washout Invoice"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Washout Correction"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Bypass Invoice"
                        ||headerMsg.ETGDOCUMENTCAUSE == "Circle Invoice")
                {
                    ledgerJournalTrans.OffsetAccountType = LedgerJournalACType::Ledger;

                    select firstonly integrationDocumentCause
                        where integrationDocumentCause.ETGDocumentCause == headerMsg.ETGDOCUMENTCAUSE;

                    mainAccount = integrationDocumentCause.ETGLedgerCode;
                }
                else
