                ledgerJournalTrans.OffsetLedgerDimension = ledgerDimension;
                ledgerJournalTrans.DefaultDimension = this.createDefaultDimension(businessUnitMap.ETGERPVerticle,businessUnitMap.ETGERPBusinessUnit,costCenterMap.ETGERPCostCenter,linesMsg.ETGCOMMODITY);
                ledgerJournalTrans.insert();

            }
            select * from ledgerJournalTableVal
                    where ledgerJournalTableVal.JournalNum == ledgerJournalTable.JournalNum;
        }
    }

    return ledgerJournalTableVal.JournalNum;
}

public DimensionDynamicAccount validGenerateLedgerDimension(MainAccountNum _mainAccountId, container _conData)
{
    #define.Vertical('VERTICALVALUE')
    #define.BusinessUnit('BUSINESSUNITVALUE')
    #define.LineofBusinesss('LINE_OF_BUSINESSSVALUE')
    #define.ProductService('PRODUCT_SERVICEVALUE')
    #define.PlantWarehouseOffice('PLANT_WAREHOUSE_OFFICEVALUE')
    #define.Department('DEPARTMENTVALUE')
    #define.InterCompany('INTERCOMPANYVALUE')
    #define.Contract('CONTRACTVALUE')
    #define.ProfitCenter('PROFITCENTERVALUE')
    #define.Vessel('VESSELVALUE')
    #define.Project('PROJECTVALUE')

    RecId dimAttId_MainAccount;
    MainAccount mainAccount;

    DimensionAttribute dimensionAttribute;
    DimensionAttributeValue dimensionAttributeValue;
    DimensionSetSegmentName DimensionSet;
    DimensionStorage dimStorage;

    LedgerAccountContract ledgerAccountContract = new LedgerAccountContract();
    DimensionAttributeValueContract valueContract;

    List valueContracts = new List(Types::Class);

    DimensionAttributeValueCombination dimensionAttributeValueCombination;

    mainAccount = MainAccount::findByMainAccountId(_mainAccountId);

    while select DimensionValueColumnName from dimensionAttribute
        where dimensionAttribute.DimensionValueColumnName == #Vertical
        || dimensionAttribute.DimensionValueColumnName == #BusinessUnit
        || dimensionAttribute.DimensionValueColumnName == #LineofBusinesss
        || dimensionAttribute.DimensionValueColumnName == #ProductService
        || dimensionAttribute.DimensionValueColumnName == #PlantWarehouseOffice
        || dimensionAttribute.DimensionValueColumnName == #Department
        || dimensionAttribute.DimensionValueColumnName == #InterCompany
        || dimensionAttribute.DimensionValueColumnName == #Contract
        || dimensionAttribute.DimensionValueColumnName == #ProfitCenter
        || dimensionAttribute.DimensionValueColumnName == #Vessel
        || dimensionAttribute.DimensionValueColumnName == #Project

    {
        switch(dimensionAttribute.DimensionValueColumnName)
        {
            case #Vertical:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,1));
                break;

            case #BusinessUnit:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,2));
                break;

            case #LineofBusinesss:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,3));
                break;

            case #ProductService:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,4));
                break;

            case #PlantWarehouseOffice:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,5));
                break;

            case #Department:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,6));
                break;
            case #InterCompany:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,7));
                break;

            case #Contract:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,8));
                break;

            case #ProfitCenter:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,9));
                break;

            case #Vessel:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,11));
                break;

            case #Project:
                dimensionAttributeValue = DimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute, conPeek(_conData,10));
                break;
        }
        if(dimensionAttributeValue)
        {
            valueContract = new DimensionAttributeValueContract();
            valueContract.parmName(dimensionAttribute.Name);
            valueContract.parmValue(dimensionAttributeValue.CachedDisplayValue);
            valueContracts.addEnd(valueContract);
        }
    }
    ledgerAccountContract.parmMainAccount(_mainAccountId);
    ledgerAccountContract.parmValues(valueContracts);
    dimStorage = DimensionServiceProvider::buildDimensionStorageForLedgerAccount(ledgerAccountContract);
    dimensionAttributeValueCombination = DimensionAttributeValueCombination::find(dimStorage.save());

    return dimensionAttributeValueCombination.RecId;
}

// <summary>
/// Exchange rate validation
/// </summary>
/// <param name = "_recId"></param>
/// <returns></returns>/
public ExchRate validateExchRate(int64 _recId)
{
    int64 _reference = _recId;
    ETG_ARAP_MSGHEADER headerValidate;
    Ledger ledgerOrg;
    ExchangeRateCurrencyPair exchangeRateCurrencyPair;
    ExchangeRate exchangeRate;
    LedgerJournalTrans ledgerJournalTrans;
    ExchRate exchRate, exchValue, exchValueCount;

    select * from headerValidate where headerValidate.RecId == _reference;

    if(headerValidate)
    {
        select firstonly ledgerOrg
            where ledgerOrg.AccountingCurrency == headerValidate.ETGCurrency
            && ledgerOrg.Name == headerValidate.ETGLegalEntity;
        if(ledgerOrg)
        {
            exchValue = str2Num(headerValidate.AXExchRate);
        }
        else
        {
            select firstonly ledgerOrg
                where ledgerOrg.AccountingCurrency != headerValidate.ETGCurrency
                && ledgerOrg.Name == headerValidate.ETGLegalEntity;

            if(ledgerOrg)
            {
                if(str2Date(headerValidate.AXDocDate, 321) == today())
                {
                    select * from exchangeRateCurrencyPair
                    where exchangeRateCurrencyPair.ExchangeRateType == ledgerOrg.DefaultExchangeRateType
                    && exchangeRateCurrencyPair.FromCurrencyCode == headerValidate.ETGCurrency
                        && exchangeRateCurrencyPair.ToCurrencyCode == ledgerOrg.AccountingCurrency;

                    if(exchangeRateCurrencyPair)
                    {
                        exchRate = exchangeRate::findByDate(exchangeRateCurrencyPair.RecId,
                                       str2Date(headerValidate.AXDocDate, 321)).ExchangeRate;
                        if(!exchRate)
                        {
                            throw error("Exchange rate of Currency"+  headerValidate.ETGCurrency +" is not available in D365.");
                        }
                    }
                }
                else if(str2Date(headerValidate.AXDocDate,321) != today())
                {
                    select * from exchangeRateCurrencyPair
                    where exchangeRateCurrencyPair.ExchangeRateType == ledgerOrg.DefaultExchangeRateType
                    && exchangeRateCurrencyPair.FromCurrencyCode == headerValidate.ETGCurrency
                        && exchangeRateCurrencyPair.ToCurrencyCode == ledgerOrg.AccountingCurrency;

                    if(exchangeRateCurrencyPair)
                    {
                        exchRate = exchangeRate::findByDate(exchangeRateCurrencyPair.RecId,
                                       str2Date(headerValidate.AXDocDate, 321)).ExchangeRate;
                        if(!exchRate)
                        {
                            throw error("Exchange rate of Currency"+  headerValidate.ETGCurrency +" is not available in D365.");
                        }
                    }
                }
            }
        }
    }
    if(exchValue)
    {
        return exchValue*100;
    }
    else
    {
        if(exchRate)
        {
            exchValueCount = exchRate/100;
        }
        return exchValueCount*100;
    }
}

/// <summary>
///
/// </summary>
/// <param name = "vertical"></param>
/// <param name = "businessUnit"></param>
/// <param name = "profitCenter"></param>
/// <returns></returns>
public DimensionDefault createDefaultDimension(str vertical, str businessUnit, str profitCenter, str product_Service)
{
    DimensionAttributeValueSetStorage   valueSetStorage = new DimensionAttributeValueSetStorage();
    DimensionDefault                    result;
    int                     i;
    DimensionAttribute      dimensionAttribute;
    DimensionAttributeValue dimensionAttributeValue;

    container               conAttr = ["Vertical","BusinessUnit","ProfitCenter","Product_Service"];
    container               conValue = [vertical, businessUnit, profitCenter, product_Service];

    str                     dimValue;

    for (i = 1; i <= conLen(conAttr); i++)
    {
        dimensionAttribute = dimensionAttribute::findByName(conPeek(conAttr,i));
        if (dimensionAttribute.RecId == 0)
        {
            continue;
        }
        dimValue = conPeek(conValue,i);
        if (dimValue != "")
        {
            dimensionAttributeValue = dimensionAttributeValue::findByDimensionAttributeAndValue(dimensionAttribute,dimValue,false,true);
            valueSetStorage.addItem(dimensionAttributeValue);
        }
    }

    result = valueSetStorage.save();
    //It reutrns the value of type DimensionDefault
    return result;
}

/// <summary>
///
/// </summary>
/// <param name = "_ARAPRef"></param>
/// <returns></returns>
public str PostVCH(str _ARAPRef)
{
    str arAPRef = _ARAPRef;

    ETG_ARAP_MSGHEADER headerMsg;
    ETG_ARAP_MSGLINES linesMsg;

    LedgerJournalTable ledgerJournalTable,ledgerJournalTableVal;
    LedgerJournalTrans ledgerJournalTrans;
    LedgerJournalName ledgerJournalName;
    CustTable custTable, custTableLoc;
    VendTable vendTable, vendTableLoc;
    NumberSeq numberseq;
    Voucher voucher;
    DimensionDynamicAccount ledgerDim;
    str integrationMessage;
    ETGIntegrationJournalTypes journalTypes;
    ETG_CXCERPBusinessUnitMapping businessUnitMap;
    ETG_CXCERPCostCenterMapping costCenterMap;
    InventTable inventTableLoc;
    InventPosting inventPosting, inventPostingLoc;
    ETGIntegrationDocumentCause integrationDocumentCause;
    VendPaymFee vendPaymFee;
    ETGIntegrationCogsLedger cogsLedgerVCH;
    str mainAccount;

    select * from headerMsg where headerMsg.ETGARAPREF == arAPRef;

    changecompany(headerMsg.ETGLegalEntity)
    {
        select * from journalTypes
               where journalTypes.ETGDocuType == headerMsg.ETGDocuType;

        select firstonly ledgerJournalName
               where ledgerJournalName.JournalName == journalTypes.ETGJournalType;

        select firstonly businessUnitMap
               where businessUnitMap.ETGCXCProfitCenter == headerMsg.ETGPROFITCENTERGR;

        select firstonly costCenterMap
               where costCenterMap.ETGCXCProfitCenter == headerMsg.ETGPROFITCENTERGR;
        // Header
        ledgerJournalTable = null;
        ledgerJournalTable.company(headerMsg.ETGLegalEntity);
        ledgerJournalTable.JournalName = ledgerJournalName.JournalName;
        ledgerJournalTable.initFromLedgerJournalName();
        ledgerJournalTable.NumberSequenceTable = ledgerJournalName.NumberSequenceTable;
        ledgerJournalTable.insert();

        if (ledgerJournalTable.RecId)
        {
            while select * from linesMsg
             where linesMsg.AxIntegrationHeaderRecId == headerMsg.AXHeaderRecId
            {
                // Line
                ledgerJournalTrans = null;
                ledgerJournalTrans.Company = headerMsg.ETGLegalEntity;
                ledgerJournalTrans.JournalNum = ledgerJournalTable.JournalNum;
                ledgerJournalTrans.TransDate = str2Date(headerMsg.AXDocDate, 321);
                ledgerJournalTrans.DocumentDate = str2Date(headerMsg.AXDocDate, 321);
                ledgerJournalTrans.Due = str2Date(headerMsg.AXDueDate, 321);
                ledgerJournalTrans.LineNum = LedgerJournalTrans::lastLineNum(ledgerJournalTrans.JournalNum);

                voucher = new JournalVoucherNum(JournalTableData::newTable(ledgerJournalTable)).getNew(true);

                ledgerJournalTrans.Voucher = voucher;
                ledgerJournalTrans.CurrencyCode = linesMsg.ETGCURRENCY;
                ledgerJournalTrans.Txt = linesMsg.ETGDESCRIPTION + "QTY" + headerMsg.AXTotalQty;
                ledgerJournalTrans.Qty = str2Num(headerMsg.AXTotalQty);

                //ledgerJournalTrans.AmountCurCredit = abs(str2Num(linesMsg.AxAmount));
                if(str2num(linesMsg.AxAmount) > 0)
                {
                    ledgerJournalTrans.AmountCurCredit = abs(str2num(linesMsg.AxAmount));
                    ledgerJournalTrans.AmountCurDebit = 0.00;
                }
                else if(str2num(linesMsg.AxAmount) < 0)
                {
                    ledgerJournalTrans.AmountCurDebit = abs(str2num(linesMsg.AxAmount));
                    ledgerJournalTrans.AmountCurCredit = 0.00;
                }

                ledgerJournalTrans.Invoice = headerMsg.ETGARAPREF;
                ledgerJournalTrans.Payment = headerMsg.ETGPAYMTERMS;
